class AppHealthLogging {
  static void install({
    bool enable = false,
    LogSink? sink,
    bool captureFlutterErrors = true,
    bool capturePlatformErrors = true,
  }) {
    ProdLogger.enabled = enable;
    if (sink != null) ProdLogger.sink = sink;

    if (!enable) return;

    if (captureFlutterErrors) {
      FlutterError.onError = (details) {
        ProdLogger.error(
          'FlutterError',
          error: details.exception,
          stack: details.stack,
          meta: {
            'library': details.library,
            'context': details.context?.toDescription(),
            'informationCollector': details.informationCollector?.call().map((n) => n.toString()).toList(),
          },
        );
        FlutterError.presentError(details);
      };
    }

    if (capturePlatformErrors) {
      PlatformDispatcher.instance.onError = (error, stack) {
        ProdLogger.error('Uncaught platform error', error: error, stack: stack);
        return false;
      };
    }

    ProdLogger.info('App health logging installed', meta: {
      'enabled': ProdLogger.enabled,
      'mode': kReleaseMode ? 'release' : (kProfileMode ? 'profile' : 'debug'),
      'platform': Platform.operatingSystem,
      'dart': Platform.version,
    });
  }
}